33	function parseNameFlag(argv) {
34	  const idx = argv.indexOf('--name');
35	  if (idx === -1) return 'world';
36	  const value = argv[idx + 1];
37	  if (!value || value.startsWith('-')) {
38	    console.error('--name requires a value');
39	    process.exit(1);
40	  }
41	  return value;
42	}
43	
44	function parseFormatFlag(argv) {
45	  const idx = argv.indexOf('--format');
46	  if (idx === -1) return undefined;
47	  const value = argv[idx + 1];
48	  if (value !== 'json') {
49	    console.error('--format must be json');
50	    process.exit(1);
51	  }
52	  return value;
53	}
