55	function main(argv) {
56	  const [command, ...rest] = argv;
57	
58	  if (!command || command === '--help' || command === '-h') {
59	    process.stdout.write(USAGE);
60	    return;
61	  }
62	
63	  switch (command) {
64	    case 'hello': {
65	      // TODO: consider supporting a --greeting flag later — out of scope for now.
66	      const name = parseNameFlag(rest);
67	      console.log(`Hello, ${name}!`);
68	      return;
69	    }
70	    case 'version': {
71	      const format = parseFormatFlag(rest);
72	      if (format === 'json') {
73	        console.log(JSON.stringify({ version: readPackageVersion() }));
74	      } else {
75	        console.log(readPackageVersion());
76	      }
77	      return;
78	    }
79	    default:
80	      console.error(`Unknown command: ${command}`);
81	      process.stderr.write(USAGE);
82	      process.exit(1);
